using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
const int MAXN=2e5+10;
ll n,c,a[MAXN],ans;
int main(void)
{
    scanf("%lld%lld",&n,&c);
    for(int i=1;i<=n;++i)
    {
        scanf("%lld",&a[i]);
    }
    sort(a+1,a+1+n);
    int r1=1,r2=1;
    for(int l=1;l<=n;++l)
    {
        while(r1<=n&&a[r1]-a[l]<c)++r1;
        while(r2<=n&&a[r2]-a[l]<=c)++r2;
        if(a[r1]-a[l]==c&&a[r2-1]-a[l]==c)
            ans+=abs(r2-r1);
    }
    printf("%lld", ans);
    return false;
}
